<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> stdout </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> child</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stdout</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">take</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;no stdout handle&quot;</span><span style="color:#9399B2;">);</span></span>
